final:
module top_module(
	input rst,
	input clk_i,
	input [15:0] div,
	output clk_o
	);reg clk_not = 1'b0;
	reg [15:0] count = 16'h0;

	always @(posedge clk_i) begin

		if(rst) begin
			clk_not = 1'b0;
			count = 16'h0;			
		end
		else begin
			count = count + 1;
			if(count == div) begin
				count = 16'h0;
				clk_not = ~clk_not;
			end
		end
	end

	assign clk_o = clk_not;

endmodule
